PROGRAM MotorStarDelta
VAR_INPUT
    Start_btn : BOOL;
    Stop_btn : BOOL;
    Overload : BOOL;
END_VAR
VAR_OUTPUT
    Main_Contactor : BOOL;
    Star_Contactor : BOOL;
    Delta_Contactor : BOOL;
    Fault : BOOL;
END_VAR
VAR
    start_rtrig : R_TRIG;
    t_star_delay : TON;
    motor_running : BOOL;
END_VAR

Fault := Overload;

start_rtrig(CLK := Start_btn);

IF Stop_btn OR Overload THEN
    motor_running := FALSE;
    Main_Contactor := FALSE;
    Star_Contactor := FALSE;
    Delta_Contactor := FALSE;
ELSIF start_rtrig.Q AND NOT Stop_btn AND NOT Overload THEN
    motor_running := TRUE;
    Main_Contactor := TRUE;
    Star_Contactor := TRUE;
    Delta_Contactor := FALSE;
ELSIF motor_running THEN
    Main_Contactor := TRUE;
    IF t_star_delay.Q THEN
        Star_Contactor := FALSE;
        Delta_Contactor := TRUE;
    ELSE
        Star_Contactor := TRUE;
        Delta_Contactor := FALSE;
    END_IF;
END_IF;

t_star_delay(IN := motor_running, PT := T#3S);
END_PROGRAM

TYPE ConveyorState : (ST_IDLE, ST_RUNNING, ST_REJECTING, ST_FAULT); END_TYPE

PROGRAM SortingConveyor
VAR_INPUT
    StartCmd      : BOOL;
    SensorPresent : BOOL;
    SensorDefect  : BOOL;
    EStop         : BOOL;
END_VAR
VAR_OUTPUT
    MotorRun        : BOOL;
    RejectSolenoid  : BOOL;
END_VAR
VAR
    State         : ConveyorState := ST_IDLE;
    RejectTimer   : TON;
END_VAR

IF EStop THEN
    State := ST_FAULT;
ELSE
    CASE State OF
        ST_IDLE:
            IF StartCmd THEN
                State := ST_RUNNING;
            END_IF;
        ST_RUNNING:
            IF SensorPresent AND SensorDefect THEN
                State := ST_REJECTING;
            END_IF;
        ST_REJECTING:
            IF RejectTimer.Q THEN
                State := ST_RUNNING;
            END_IF;
        ST_FAULT:
            State := ST_IDLE;
    END_CASE
END_IF

IF State = ST_REJECTING THEN
    RejectTimer(IN := TRUE, PT := T#500MS);
ELSE
    RejectTimer(IN := FALSE);
END_IF

MotorRun        := (State = ST_RUNNING);
RejectSolenoid  := (State = ST_REJECTING);
END_PROGRAM

