FUNCTION_BLOCK PID_Temperature
VAR_INPUT
    Enable : BOOL;
    Setpoint : REAL;
    ProcessValue : REAL;
    Kp : REAL := 2.0;
    Ki : REAL := 0.05;
    Kd : REAL := 0.0;
    CycleTime : TIME := T#100ms;
END_VAR
VAR_OUTPUT
    Output : REAL;
END_VAR
VAR
    Ts : REAL;
    Error : REAL;
    PrevError : REAL;
    Integral : REAL;
    Derivative : REAL;
    CalcOutput : REAL;
END_VAR

Ts := TIME_TO_REAL(CycleTime);
Error := Setpoint - ProcessValue;

IF NOT Enable THEN
    Output := 0.0;
    Integral := 0.0;
    PrevError := 0.0;
ELSE
    Integral := Integral + Ki * Ts * Error;
    Derivative := Kd * (Error - PrevError) / Ts;
    CalcOutput := Kp * Error + Integral + Derivative;

    IF CalcOutput < 0.0 THEN
        Output := 0.0;
    ELSIF CalcOutput > 100.0 THEN
        Output := 100.0;
    ELSE
        Output := CalcOutput;
    END_IF;

    PrevError := Error;
END_IF;
END_FUNCTION_BLOCK
