PROGRAM PumpLeadLag
VAR_INPUT
    LevelLow      : BOOL;
    LevelHigh     : BOOL;
    Pump1Fault    : BOOL;
    Pump2Fault    : BOOL;
    ManualMode    : BOOL;
    ManualP1Run   : BOOL;
    ManualP2Run   : BOOL;
END_VAR

VAR_OUTPUT
    P1Run : BOOL;
    P2Run : BOOL;
END_VAR

VAR
    LeadPump : INT := 1;
END_VAR

IF ManualMode THEN
    P1Run := ManualP1Run;
    P2Run := ManualP2Run;
ELSE
    IF LeadPump = 1 AND Pump1Fault AND NOT Pump2Fault THEN
        LeadPump := 2;
    ELSIF LeadPump = 2 AND Pump2Fault AND NOT Pump1Fault THEN
        LeadPump := 1;
    END_IF;

    IF LevelLow THEN
        IF LeadPump = 1 THEN
            P1Run := TRUE;
            P2Run := FALSE;
        ELSE
            P1Run := FALSE;
            P2Run := TRUE;
        END_IF;
    ELSIF LevelHigh THEN
        P1Run := FALSE;
        P2Run := FALSE;
    END_IF;
END_IF;
END_PROGRAM
