PROGRAM BatchDoseSequence
VAR_INPUT
    StartSeq : BOOL;
    Abort    : BOOL;
END_VAR
VAR_OUTPUT
    Valve1   : BOOL;
    Valve2   : BOOL;
    Valve3   : BOOL;
    SeqDone  : BOOL;
    SeqActive: BOOL;
END_VAR
VAR
    Step          : INT := 0;
    Timer1        : TON;
    Timer2        : TON;
    Timer3        : TON;
    StartSeqPrev  : BOOL := FALSE;
END_VAR

IF Abort THEN
    Step := 0;
    Valve1 := FALSE;
    Valve2 := FALSE;
    Valve3 := FALSE;
    SeqDone := FALSE;
    SeqActive := FALSE;
    Timer1(IN := FALSE, PT := T#2s);
    Timer2(IN := FALSE, PT := T#3s);
    Timer3(IN := FALSE, PT := T#1s);
    StartSeqPrev := FALSE;
    RETURN;
END_IF;

IF StartSeq AND NOT StartSeqPrev THEN
    IF Step = 0 THEN
        Step := 1;
    END_IF;
END_IF;
StartSeqPrev := StartSeq;

CASE Step OF
    0:
        Valve1 := FALSE; Valve2 := FALSE; Valve3 := FALSE;
        SeqDone := FALSE; SeqActive := FALSE;
        Timer1(IN := FALSE, PT := T#2s);
        Timer2(IN := FALSE, PT := T#3s);
        Timer3(IN := FALSE, PT := T#1s);

    1:
        Valve1 := TRUE; Valve2 := FALSE; Valve3 := FALSE;
        SeqDone := FALSE; SeqActive := TRUE;
        Timer1(IN := TRUE, PT := T#2s);
        Timer2(IN := FALSE, PT := T#3s);
        Timer3(IN := FALSE, PT := T#1s);
        IF Timer1.Q THEN Step := 2; END_IF;

    2:
        Valve1 := FALSE; Valve2 := TRUE; Valve3 := FALSE;
        SeqDone := FALSE; SeqActive := TRUE;
        Timer1(IN := FALSE, PT := T#2s);
        Timer2(IN := TRUE, PT := T#3s);
        Timer3(IN := FALSE, PT := T#1s);
        IF Timer2.Q THEN Step := 3; END_IF;

    3:
        Valve1 := FALSE; Valve2 := FALSE; Valve3 := TRUE;
        SeqDone := FALSE; SeqActive := TRUE;
        Timer1(IN := FALSE, PT := T#2s);
        Timer2(IN := FALSE, PT := T#3s);
        Timer3(IN := TRUE, PT := T#1s);
        IF Timer3.Q THEN Step := 4; END_IF;

    4:
        Valve1 := FALSE; Valve2 := FALSE; Valve3 := FALSE;
        SeqDone := TRUE; SeqActive := FALSE;
        Timer1(IN := FALSE, PT := T#2s);
        Timer2(IN := FALSE, PT := T#3s);
        Timer3(IN := FALSE, PT := T#1s);
END_CASE;
END_PROGRAM
