FUNCTION_BLOCK MovingAverageFilter
VAR_INPUT
    Enable : BOOL;
    RawInput : REAL;
    WindowSize : INT;
END_VAR
VAR_OUTPUT
    Filtered : REAL;
END_VAR
VAR
    Buffer : ARRAY[0..9] OF REAL;
    Head : INT;
    Count : INT;
    Sum : REAL;
    EffectiveSize : INT;
    i : INT;
END_VAR

EffectiveSize := WindowSize;
IF EffectiveSize < 1 THEN EffectiveSize := 1; END_IF;
IF EffectiveSize > 10 THEN EffectiveSize := 10; END_IF;

IF NOT Enable THEN
    FOR i := 0 TO 9 DO
        Buffer[i] := 0.0;
    END_FOR;
    Head := 0;
    Count := 0;
    Sum := 0.0;
    Filtered := 0.0;
ELSIF Enable THEN
    IF Count < EffectiveSize THEN
        Sum := Sum + RawInput;
        Count := Count + 1;
    ELSE
        Sum := Sum - Buffer[Head] + RawInput;
    END_IF;

    Buffer[Head] := RawInput;
    Head := (Head + 1) MOD EffectiveSize;
    Filtered := Sum / INT_TO_REAL(Count);
END_IF;
END_FUNCTION_BLOCK
